//AOC2018 D5


function solve(s) {
    let _s = '';
    for(let i=0; i<s.length - 1; i++) {
        let c1 = s.charCodeAt(i);
        let c2 = s.charCodeAt(i+1);
        if(Math.abs(c1 - c2) === 32){
            i += 1;
            _s = _s.slice(0, -1);
            continue;
        } 
        _s += s[i];
        if(i === s.length - 2) {
            _s += s[i+1];
        }
    }
    console.log(_s.length);
}

// solve('dabAcCaCBAcCcaDA');
solve(data());


